(function ($) {
'use strict';
var frame;
var MAX_IMAGES = (typeof vh360EventGalleryAdmin !== 'undefined' && vh360EventGalleryAdmin.maxImages)
? parseInt(vh360EventGalleryAdmin.maxImages, 10)
: 5;
function getGalleryIds() {
var ids = [];
$('#vh360-event-gallery-admin-preview .vh360-event-gallery-admin-item').each(function () {
var id = parseInt($(this).data('id'), 10);
if (id) {
ids.push(id);
}
});
return ids;
}
function syncHiddenInput() {
var ids = getGalleryIds();
$('#vh360_event_gallery_image_ids').val(ids.join(','));
updateCounter(ids.length);
}
function updateCounter(count) {
var label = (typeof vh360EventGalleryAdmin !== 'undefined' && vh360EventGalleryAdmin.i18n)
? vh360EventGalleryAdmin.i18n.maxImages
: 'You can add up to 5 gallery images.';
$('#vh360-event-gallery-admin-count').text(count + ' / ' + MAX_IMAGES + ' images selected');
var $btn = $('#vh360-event-gallery-admin-add');
if (count >= MAX_IMAGES) {
$btn.prop('disabled', true).attr('title', label);
} else {
$btn.prop('disabled', false).attr('title', '');
}
}
function appendPreviewItem(id, thumbUrl, alt) {
var removeLabel = (typeof vh360EventGalleryAdmin !== 'undefined' && vh360EventGalleryAdmin.i18n)
? vh360EventGalleryAdmin.i18n.removeImage
: 'Remove image';
var $img = $('<img>').attr('src', thumbUrl).attr('alt', alt || '');
var $btn = $('<button>').attr('type', 'button')
.addClass('vh360-event-gallery-admin-remove')
.attr('aria-label', removeLabel)
.text('\u00d7');
var $item = $('<div>').addClass('vh360-event-gallery-admin-item')
.attr('data-id', id)
.append($img)
.append($btn);
$('#vh360-event-gallery-admin-preview').append($item);
}
function openMediaFrame() {
var currentCount = getGalleryIds().length;
if (currentCount >= MAX_IMAGES) {
var msg = (typeof vh360EventGalleryAdmin !== 'undefined' && vh360EventGalleryAdmin.i18n)
? vh360EventGalleryAdmin.i18n.maxImages
: 'You can add up to 5 gallery images.';
alert(msg);
return;
}
var selectLabel = (typeof vh360EventGalleryAdmin !== 'undefined' && vh360EventGalleryAdmin.i18n)
? vh360EventGalleryAdmin.i18n.selectImages
: 'Select Event Gallery Images';
var useLabel = (typeof vh360EventGalleryAdmin !== 'undefined' && vh360EventGalleryAdmin.i18n)
? vh360EventGalleryAdmin.i18n.useImages
: 'Use Selected Images';
if (frame) {
frame.open();
return;
}
frame = wp.media({
title: selectLabel,
button: {
text: useLabel
},
library: {
type: 'image'
},
multiple: true
});
frame.on('select', function () {
var selection  = frame.state().get('selection');
var currentIds = getGalleryIds();
var remaining  = MAX_IMAGES - currentIds.length;
selection.each(function (attachment) {
if (remaining <= 0) {
return false;
}
var id = attachment.get('id');
if (currentIds.indexOf(id) !== -1) {
return;
}
var sizes    = attachment.get('sizes');
var thumbUrl = sizes && sizes.thumbnail ? sizes.thumbnail.url : attachment.get('url');
var alt      = attachment.get('alt') || '';
appendPreviewItem(id, thumbUrl, alt);
remaining--;
});
syncHiddenInput();
});
frame.open();
}
$(document).ready(function () {
$(document).on('click', '#vh360-event-gallery-admin-add', function (e) {
e.preventDefault();
openMediaFrame();
});
$(document).on('click', '.vh360-event-gallery-admin-remove', function () {
$(this).closest('.vh360-event-gallery-admin-item').remove();
syncHiddenInput();
});
syncHiddenInput();
});
}(jQuery));
